// Get deal, then fetch the associated contact
const deal = $input.first().json;
const contactId = deal.associations?.contacts?.results?.[0]?.id;
const props = deal.properties || {};

return [{ json: {
  dealId: deal.id,
  contactId: contactId || null,
  companyName: props.dealname?.replace('Hiring Signal: ', '') || '',
  jobTitle: props.job_title_detected || '',
  numOpenings: parseInt(props.num_openings) || 10,
  jobUrl: props.job_posting_url || '',
  description: props.description || '',
  contractValue: props.estimated_contract_value || '$100K'
} }];

// Merge deal + contact data
const contact = $input.first().json;
const deal = $('Extract Deal Data').item.json;
const cp = contact.properties || {};

return [{ json: {
  ...deal,
  dmName: `${cp.firstname || ''} ${cp.lastname || ''}`.trim() || 'Operations Leader',
  dmTitle: cp.jobtitle || 'VP Operations',
  dmEmail: cp.email || '',
  dmLinkedin: cp.linkedin_url || ''
} }];

// Parse ROI result
const response = $input.first().json;
const data = $('Merge Data').item.json;
let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

let roi;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  roi = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  roi = { hiring: { total_annual: 500000 }, feather: { total_annual_cost: 80000 }, savings: { annual: 420000, pct: 84, payback_months: 2 }, headline: 'Significant cost savings with AI voice agents' };
}

return [{ json: { ...data, roi } }];

// Parse outreach drafts
const response = $input.first().json;
const data = $('Parse ROI').item.json;
let text = '';
if (response.content && Array.isArray(response.content)) {
  text = response.content.filter(b => b.type === 'text').map(b => b.text).join('\n');
}

let msgs;
try {
  const cleaned = text.replace(/```json|```/g, '').trim();
  const match = cleaned.match(/\{[\s\S]*\}/);
  msgs = JSON.parse(match ? match[0] : cleaned);
} catch (e) {
  msgs = { email: { subject: 'Parse error', body: text }, linkedin: { connection_note: '', followup: '' }, linkedin_post: '', one_liner: '' };
}

return [{ json: { ...data, outreach: msgs } }];

